mapper.sql:
WITH latest_assignment AS ( SELECT mra.id AS assignment_id, mra.role_id AS role_id, mp.sensitive_field_id AS sensitive_field_id, mp.id AS policy_id, mp.masking_type AS masking_type, CAST(mp.params AS CHAR) AS params, mtd.type_name AS masking_type_name, ROW_NUMBER() OVER ( PARTITION BY mra.role_id, mp.sensitive_field_id ORDER BY mra.id DESC, mp.id DESC ) AS rn FROM masking_rule_assignment mra JOIN masking_policy mp ON mp.id = mra.policy_id LEFT JOIN masking_type_dict mtd ON mtd.type_code = mp.masking_type WHERE mra.enabled = 1 ) SELECT r.id AS role_id, r.role_code AS role_code, r.role_name AS role_name, sf.id AS sensitive_field_id, sf.table_name AS table_name, sf.column_name AS column_name, CONCAT(sf.table_name, '.', sf.column_name) AS field_label, sf.sensitive_type AS sensitive_type, sf.sensitive_level AS sensitive_level, la.assignment_id AS assignment_id, la.policy_id AS assigned_policy_id, la.masking_type AS assigned_masking_type, la.masking_type_name AS assigned_masking_type_name, la.params AS assigned_params, dp.id AS default_policy_id, dp.masking_type AS default_masking_type, dtd.type_name AS default_masking_type_name, CAST(dp.params AS CHAR) AS default_params FROM role r CROSS JOIN sensitive_field sf LEFT JOIN latest_assignment la ON la.role_id = r.id AND la.sensitive_field_id = sf.id AND la.rn = 1 LEFT JOIN masking_policy dp ON dp.sensitive_field_id = sf.id AND dp.is_default = 1 LEFT JOIN masking_type_dict dtd ON dtd.type_code = dp.masking_type WHERE r.enabled = 1 AND sf.enabled = 1
AND r.id = #{roleId}
AND sf.id = #{sensitiveFieldId}

mapper.select:
SELECT sensitive_field_id
FROM masking_policy
WHERE id = #{policyId}

SELECT id
FROM masking_rule_assignment
WHERE role_id = #{roleId}
  AND policy_id = #{policyId}
LIMIT 1

mapper.update:
UPDATE masking_rule_assignment mra
JOIN masking_policy mp ON mp.id = mra.policy_id
SET mra.enabled = 0
WHERE mra.role_id = #{roleId}
  AND mp.sensitive_field_id = #{sensitiveFieldId}

UPDATE masking_rule_assignment
SET enabled = #{enabled}
WHERE id = #{id}
